<style scoped>
.hero-keyboard-wrapper {
    user-select: none;
    -webkit-user-select: none;
}

.hero-keyboard {
    cursor: pointer;
}

/* --- Terminal readout --- */
.terminal {
    font-size: 0.9rem;
    letter-spacing: 0.02em;
    color: rgba(242, 219, 193, 0.7);
    min-height: 1.4em;
}

.terminal__prompt {
    color: var(--color-coral);
}

.terminal__text {
    color: var(--color-cream);
}

.terminal__caret {
    display: inline-block;
    margin-left: 1px;
    color: var(--color-cream);
}

.terminal__caret--blink {
    animation: caretBlink 1s step-end infinite;
}

@keyframes caretBlink {
    0%, 49% { opacity: 1; }
    50%, 100% { opacity: 0; }
}

/* --- Dot key ripple --- */
.dot-ripple-layer {
    pointer-events: none;
}

.dot-ripple {
    fill: none;
    stroke: var(--color-cream);
    stroke-width: 1.5;
    transform-box: fill-box;
    transform-origin: center;
    animation: dotRipple 0.75s ease-out forwards;
}

.dot-ripple--delayed {
    animation-delay: 0.12s;
    opacity: 0;
}

@keyframes dotRipple {
    0% {
        r: 3;
        opacity: 0.9;
        stroke-width: 2;
    }
    100% {
        r: 55;
        opacity: 0;
        stroke-width: 0.5;
    }
}

.key > :not(.key__shadow) {
    transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
    transform-origin: center center;
}

.key:hover > :not(.key__shadow) {
    filter: brightness(1.03);
}

.key--pressed > :not(.key__shadow) {
    transform: translate(1.5px, 3px);
}

.key--pressed path[fill="#F2DBC1"] {
    opacity: 0.4;
}

.key__shadow {
    transform: translate(0, 4px);
    transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
    filter: brightness(0);
    opacity: 0.33;
    pointer-events: none;
}

.key--pressed .key__shadow {
    transform: translate(1.5px, 3.5px);
}
</style>
